export async function handleReset(ctx: Context): Promise<void> {
  const { isAllowed, sessions, saveTranscript } = deps();
  if (!isAllowed(ctx)) return;
  const chatId = ctx.chat!.id;
  const arg = ((ctx as any).match?.trim?.() ?? "").toLowerCase();
  const clean = arg === "clean" || arg === "fresh";

  const session = sessions.peek(chatId);
  if (session && session.history.length > 0) {
    try {
      const filename = await saveTranscript(session);
      await ctx.reply(`Saved → sessions/${filename}`);
    } catch {}
  }
  await sessions.drop(chatId, "reset");
  clearDedupCache(chatId);

  // Clean mode: delete archive + working-state so next session starts fresh.
  if (clean) {
    const { deleteArchive } = await import("../session-archive.js");
    const { unlink } = await import("node:fs/promises");
    const path = await import("node:path");
    const { config } = await import("../config.js");
    await deleteArchive(chatId);
    await unlink(path.join(config.memoryDir, `working-state-${chatId}.md`)).catch(() => {});
    await ctx.reply("Session reset (clean). 下次對話不會帶入上次上下文。");
  } else {
    await ctx.reply("Session reset.");
  }
}

export async function handleCancel(ctx: Context): Promise<void> {
  const { isAllowed, sessions } = deps();
  if (!isAllowed(ctx)) return;
  const chatId = ctx.chat!.id;
  const arg = (ctx as any).match?.trim?.() ?? "";

  if (arg.toLowerCase() === "all") {
    sessions.enableDropAll(chatId);
    sessions.cancel(chatId);
    await ctx.reply("✅ Cancel all: 已取消當前回合，排隊中的訊息將被丟棄。");
    return;
  }

  const session = sessions.peek(chatId);
  const placeholderMsgId = session?._placeholderMsgId;
  sessions.cancel(chatId);

  // Edit the placeholder to show partial output + cancellation notice
  if (placeholderMsgId) {
    const partial = (session!.buffer || "").trim();
    const text = partial
      ? `${partial}\n\n⛔ _(已取消)_`
      : "⛔ 已取消。";
    try {
      await ctx.api.editMessageText(chatId, placeholderMsgId, text);
    } catch { /* message may already be gone or identical */ }
  }
  await ctx.reply("✅ 已取消，可以繼續對話。");
}

  // Archive session state before closing (summary + trivial carry-forward)
  if (s.history.length > 0 || s.priorArchive) {
    await this.archiveOnClose(s, closeReason);
  }
  if (this.onBeforeClose) {
    try { await this.onBeforeClose(s); } catch (e) {
      console.error(`[session ${chatId}] onBeforeClose failed:`, e);
    }
  }
  await s.client.close();
}

/**
 * Park — 暫停 session（/session 切換用）：關 subprocess、record 保留，
 * 之後可 session/load 切回。與 drop() 對照：drop = fresh 意圖（清 active
 * record + archive + onBeforeClose 全套收尾），park 刻意都不做——
 * onBeforeClose 含 writeWorkingState("session closed") + saveArchive，
 * archive 會被下次 create 消費刪除且 resume 路徑直接丟棄（純汙染）。
 * 但單獨存 transcript（fire-and-forget），讓 parked 段落仍進 memory
 * extraction 素材。無活 session 時 no-op（idle sweep 已收掉的場景）。
 */
async park(chatId: number): Promise<void> {
  const s = this.sessions.get(chatId);
  if (!s) return;
  // 先移出 map：provider exit handler 以 map 內容判斷是否 unexpected
  this.sessions.delete(chatId);
  logEvent("session_end", { reason: "park" }, { chatId, userId: s.userId });
  if (s.history.length > 0) {
    // dynamic import 防 sessionManager ⇄ session-extract 循環依賴
    import("./session-extract.js")
      .then((m) => m.saveTranscript(s))
      .catch((e) => console.warn(`[session ${chatId}] park transcript failed:`, e));
  }
  await s.client.close();
}

/**
 * /session 切換：park 現行 → setActive → create()（resolveResumeCandidate
 * 自然命中新 active，走 session/load 恢復目標 context）。
 * 順序防呆：① 目標先驗證存在（read-only，不存在時現行 session 不受影響）
 * ② store 寫入（setActive）必須在 park 成功之後——反過來的話 park 失敗
 * 會留下「store 指 target、map 還是舊 session」的 divergence。
 * create 失敗則 map 無 session、active 已指 target → 下一則訊息 get() 自癒。
 */
async switchSession(chatId: number, targetId: string, userId?: number): Promise<ChatSession> {
  const { activeId, sessions: records } = await listSessions(chatId);
  const target = records.find((r) => r.id === targetId);
  if (!target) {
    throw new Error(`找不到 session ${targetId}（可能已被移除），請重開 /session 列表`);
  }
  const existing = this.sessions.get(chatId);
  if (existing?.inflight) {
    throw new Error("目前有 turn 進行中，請等它完成或先 /cancel 再切換");
  }
  if (targetId === activeId && existing && !existing.client.isClosed) {
    return existing; // 已是 active 且進程活著：no-op
  }
  if (existing) {
    await this.park(chatId);
  }

