   296→      .filter(e => e.role === "assistant")
   297→      .slice(-5)
   298→      .map(e => e.text);
   299→    const allText = assistantMsgs.join("\n");
   300→    for (const line of allText.split("\n")) {
   301→      const m = line.match(/\[WS\]\s*(task|completed|blocked|key_refs|next_action):\s*(.+)/i);
   302→      if (!m) continue;
   303→      const [, field, value] = m;
   304→      const v = value.trim();
   305→      switch (field.toLowerCase()) {
   306→        case "task": ws.task = v; break;
   307→        case "completed": ws.completed.push(v); break;
   308→        case "blocked": ws.blocked.push(v); break;
   309→        case "key_refs": ws.key_refs.push(v); break;
   310→        case "next_action": ws.next_action = v; break;
   311→      }
   312→    }
   313→  }
   314→
   315→  let md = `# Working State\n\n`;
   316→  md += `- chatId: ${ws.chatId}\n`;
   317→  md += `- savedAt: ${ws.savedAt}\n`;
   318→  if (ws.restartReason) md += `- restartReason: ${ws.restartReason}\n`;
   319→  md += `- task: ${ws.task}\n`;
   320→  md += `- phase: ${ws.phase}\n`;
   321→  md += `- next_action: ${ws.next_action}\n`;
   322→  md += `\n`;
   323→
   324→  if (ws.completed.length > 0) {
   325→    md += `## Completed\n`;
   326→    md += ws.completed.map(c => `- ${c}`).join("\n") + "\n\n";
   327→  }
   328→  if (ws.blocked.length > 0) {
   329→    md += `## Blocked\n`;
   330→    md += ws.blocked.map(b => `- ${b}`).join("\n") + "\n\n";
   331→  }
   332→  if (ws.key_refs.length > 0) {
   333→    md += `## Key References\n`;
   334→    md += ws.key_refs.map(r => `- ${r}`).join("\n") + "\n\n";
   335→  }
   336→  if (recentLines.length > 0) {
   337→    md += `## Recent Context\n`;
   338→    md += recentLines.slice(-5).join("\n") + "\n\n";
   339→  }
   340→
   341→  const filePath = path.join(MEMORY_DIR, `working-state-${chatId}.md`);
   342→  await writeFile(filePath, md, "utf8");
   343→  console.log(`[restart] wrote working-state for chat ${chatId}`);
   344→}
   345→

