/**
 * Token 執行權限顯式 policy 表。
 *
 * 設計意圖：「權限靠宣告不靠遺漏」。
 * 目前 proxy specialist 輸出的危險 token（SCHEDULE / RESTART / MOA_PLAN 等）
 * 只是剛好攝取點沒呼叫對應邏輯——未來 refactor 可能誤開。
 * 此模組以白名單形式宣告每個來源可以執行哪些 token kind，
 * filterTransformedByPolicy 在攝取點統一攔截非法 token。
 */

import type { TransformedReply } from "./observerTransformer.js";

// ─── 型別 ─────────────────────────────────────────────────────────────────────

/** Token 來源。 */
export type TokenSource = "main" | "proxy" | "delegate";

/** 所有可辨識的 token 種類（與 TransformedReply 欄位一一對應）。 */
export type TokenKind =
  | "sendFiles"
  | "scheduleTokens"
  | "askTokens"
  | "skillUsages"
  | "goalDone"
  | "restartToken"
  | "stickerEmotions"
  | "skillPropose"
  | "wikiQuery"
  | "continueToken"
  | "specialistProxy"
  | "moaPlan"
  | "rememberFacts";

// ─── Policy 表 ────────────────────────────────────────────────────────────────

/**
 * 各來源允許執行的 token 白名單。
 * - main：全部開放（主 agent 路徑完全信任）。
 * - proxy：僅限安全的 UI / 記憶類 token。
 * - delegate：delegate 輸出只當文字注入主 agent，不執行任何 token。
 */
export const TOKEN_POLICY: Record<TokenSource, ReadonlySet<TokenKind>> = {
  main: new Set<TokenKind>([
    "sendFiles",
    "scheduleTokens",
    "askTokens",
    "skillUsages",
    "goalDone",
    "restartToken",
    "stickerEmotions",
    "skillPropose",
    "wikiQuery",
    "continueToken",
    "specialistProxy",
    "moaPlan",
    "rememberFacts",
  ]),
  proxy: new Set<TokenKind>([
    "sendFiles",
    "askTokens",
    "skillUsages",
    "stickerEmotions",
    "rememberFacts",
  ]),
  delegate: new Set<TokenKind>([]),
};

// ─── 過濾函式 ─────────────────────────────────────────────────────────────────

/** 每個 token kind 對應 TransformedReply 中的欄位名稱與歸零值的映射。 */
const FIELD_ZERO: Record<Exclude<TokenKind, "rememberFacts">, { key: keyof TransformedReply; zero: unknown }> = {
  sendFiles:       { key: "sendFiles",       zero: [] },
  scheduleTokens:  { key: "scheduleTokens",  zero: [] },
  askTokens:       { key: "askTokens",       zero: [] },
  skillUsages:     { key: "skillUsages",     zero: [] },
  goalDone:        { key: "goalDone",        zero: null },
  restartToken:    { key: "restartToken",    zero: null },
  stickerEmotions: { key: "stickerEmotions", zero: [] },
  skillPropose:    { key: "skillPropose",    zero: null },
  wikiQuery:       { key: "wikiQuery",       zero: null },
  continueToken:   { key: "continueToken",   zero: false },
  specialistProxy: { key: "specialistProxy", zero: null },
  moaPlan:         { key: "moaPlan",         zero: null },
};

/**
 * 依 policy 過濾 TransformedReply：不在允許集合的欄位強制歸零。
 * 回傳淺拷貝，不修改原物件。text 保持不變。
 */
export function filterTransformedByPolicy(
  reply: TransformedReply,
  source: TokenSource,
): TransformedReply {
  const allowed = TOKEN_POLICY[source];
  const filtered: TransformedReply = { ...reply };
  const dropped: string[] = [];

  for (const [kind, mapping] of Object.entries(FIELD_ZERO) as Array<
    [Exclude<TokenKind, "rememberFacts">, { key: keyof TransformedReply; zero: unknown }]
  >) {
    if (allowed.has(kind)) continue;
    // 判斷原欄位是否有非空內容
    const val = reply[mapping.key];
    const isEmpty =
      val === null ||
      val === undefined ||
      val === false ||
      (Array.isArray(val) && val.length === 0);
    if (!isEmpty) {
      dropped.push(kind);
    }
    (filtered as unknown as Record<string, unknown>)[mapping.key] = mapping.zero;
  }

  if (dropped.length > 0) {
    console.warn(`[token-policy] source=${source} dropped: ${dropped.join(",")}`);
  }

  return filtered;
}

// ─── Remember facts 上限 ─────────────────────────────────────────────────────

/** 單次 specialist 輸出允許回寫的最大 fact 條數。 */
export const REMEMBER_FACTS_MAX_PER_OUTPUT = 5;

/**
 * Working state persistence + delegation context + memory token helpers.
 * Extracted from session-extract.ts and commands/relay.ts (P5 split).
 */
import { writeFile, readFile, unlink } from "node:fs/promises";
import path from "node:path";
import type { ChatSession, SessionManager } from "./sessionManager.js";
import { config } from "./config.js";
import * as goalStore from "./goalStore.js";
import { appendFact } from "./memory.js";

// ─── Types ────────────────────────────────────────────────────────────────────

export interface WorkingState {
  chatId: number;
  savedAt: string;
  restartReason?: string;
  task: string;
  phase: string;
  completed: string[];
  blocked: string[];
  key_refs: string[];
  next_action: string;
}

export type RelayTaskDirection = "incoming" | "outgoing";
export type RelayTaskStatus = "active" | "done" | "failed" | "timeout";

export interface RelayTaskRecord {
  id: string;
  peer: string;
  direction: RelayTaskDirection;
  status: RelayTaskStatus;
  goal: string;
  context?: string;
  createdAt: string;
  updatedAt: string;
  ownerChatId?: number;
  relayChatId?: number;
  attachmentPaths: string[];
  inputPaths: string[];
  outputPaths: string[];
  resultSummary?: string;
}

// ─── Memory token helpers ─────────────────────────────────────────────────────

import { REMEMBER_FACTS_MAX_PER_OUTPUT } from "./token-policy.js";

const REMEMBER_TOKEN_RE = /<<REMEMBER:\s*([^>\r\n]+?)\s*>>/g;

/**
 * 純函式：從 specialist 輸出抽取所有 REMEMBER token 內容。
 * 超過 cap 時截斷並 warn 丟棄數量。
 */
export function parseRememberTokens(output: string, cap: number = REMEMBER_FACTS_MAX_PER_OUTPUT): string[] {
  const results: string[] = [];
  let m: RegExpExecArray | null;
  REMEMBER_TOKEN_RE.lastIndex = 0;
  while ((m = REMEMBER_TOKEN_RE.exec(output)) !== null) {
    const fact = m[1].trim();
    if (fact) results.push(fact);
  }
  if (results.length > cap) {
    const discarded = results.length - cap;
    console.warn(`[token-policy] parseRememberTokens: discarded ${discarded} facts (cap=${cap})`);
    return results.slice(0, cap);
  }
  return results;
}

/**
 * Extract and process memory tokens from specialist proxy output.
 * sourceLabel（可選）標記 provenance，寫入 fact 尾端。
 */
export function extractMemoryTokensFromProxy(output: string, userId: number, sourceLabel?: string): void {
  const facts = parseRememberTokens(output);
  for (const fact of facts) {
    const tagged = sourceLabel ? `${fact} [via specialist:${sourceLabel}]` : fact;
    appendFact(userId, tagged).catch((err) =>
      console.error(`[specialist:proxy] appendFact failed:`, err),
    );
  }
}

/** Strip memory tokens from text before displaying to user. */
export function stripMemoryTokens(text: string): string {
  return text.replace(REMEMBER_TOKEN_RE, "").replace(/\n{3,}/g, "\n\n");
}

// ─── Delegation context ───────────────────────────────────────────────────────

export async function saveDelegationContext(
  chatId: number,
  correlationId: string,
  session: ChatSession,
): Promise<void> {
  const recent = session.history.slice(-10).map((e) => {
    const prefix = e.role === "user" ? "User" : "Agent";
    return `${prefix}: ${e.text.replace(/\n/g, " ").slice(0, 120)}`;

