// Smoke test: Token Policy — 權限白名單 + parseRememberTokens 上限。
//
// 驗證：
//   1. filterTransformedByPolicy("proxy") 只保留 sendFiles/askTokens/stickerEmotions
//   2. filterTransformedByPolicy("main") 不丟棄任何欄位
//   3. parseRememberTokens 上限截斷正確
//
// Run: node scripts/check-token-policy.mjs
// Uses compiled dist/ — run `npx tsc` first.

process.env.TELEGRAM_BOT_TOKEN ||= "dummy"; // config.ts requires it

const { transform } = await import("../dist/observerTransformer.js");
const { filterTransformedByPolicy } = await import("../dist/token-policy.js");
const { parseRememberTokens } = await import("../dist/working-state.js");

const results = [];
function ok(name) {
  results.push({ name, pass: true });
  console.log(`  ✓ ${name}`);
}
function fail(name, detail) {
  results.push({ name, pass: false, detail });
  console.error(`  ✗ ${name}: ${detail}`);
}
function eq(a, b) {
  return JSON.stringify(a) === JSON.stringify(b);
}

// ─── Stub schedule parsers ─────────────────────────────────────────────────
const stubParsers = {
  parseDuration: (raw) => (raw === "30m" ? 30 * 60 * 1000 : null),
  parseAbsoluteTime: () => null,
  parseRecurrence: () => null,
  computeNextRunAt: () => null,
  now: () => 1_700_000_000_000,
};

// ═══════════════════════════════════════════════════════════════════════════════
// Test 1: filterTransformedByPolicy("proxy") 保留白名單、丟棄危險 token
// ═══════════════════════════════════════════════════════════════════════════════

console.log("\n=== Test 1: proxy policy filter ===");
{
  const input = [
    "Hello",
    "<<SEND_FILE:C:\\test\\file.png>>",
    "<<ASK:q1|a=Option A|b=Option B>>",
    "<<SCHEDULE:30m|reminder>>",
    "<<RESTART:need restart>>",
    "<<STICKER:happy>>",
  ].join("\n");

  const reply = transform(input, stubParsers);
  const filtered = filterTransformedByPolicy(reply, "proxy");

  // sendFiles 保留
  if (filtered.sendFiles.length === 1 && filtered.sendFiles[0] === "C:\\test\\file.png") {
    ok("proxy: sendFiles preserved");
  } else {
    fail("proxy: sendFiles preserved", `got ${JSON.stringify(filtered.sendFiles)}`);
  }

  // askTokens 保留
  if (filtered.askTokens.length === 1 && filtered.askTokens[0].questionId === "q1") {
    ok("proxy: askTokens preserved");
  } else {
    fail("proxy: askTokens preserved", `got ${JSON.stringify(filtered.askTokens)}`);
  }

  // stickerEmotions 保留
  if (filtered.stickerEmotions.length === 1 && filtered.stickerEmotions[0] === "happy") {
    ok("proxy: stickerEmotions preserved");
  } else {
    fail("proxy: stickerEmotions preserved", `got ${JSON.stringify(filtered.stickerEmotions)}`);
  }

  // scheduleTokens 被丟棄
  if (filtered.scheduleTokens.length === 0) {
    ok("proxy: scheduleTokens dropped");
  } else {
    fail("proxy: scheduleTokens dropped", `got length=${filtered.scheduleTokens.length}`);
  }

  // restartToken 被丟棄
  if (filtered.restartToken === null) {
    ok("proxy: restartToken dropped");
  } else {
    fail("proxy: restartToken dropped", `got ${JSON.stringify(filtered.restartToken)}`);
  }

  // text 保持不變
  if (typeof filtered.text === "string" && filtered.text.includes("Hello")) {
    ok("proxy: text preserved");
  } else {
    fail("proxy: text preserved", `text missing 'Hello'`);
  }
}

// ═══════════════════════════════════════════════════════════════════════════════
// Test 2: filterTransformedByPolicy("main") 什麼都不動
// ═══════════════════════════════════════════════════════════════════════════════

console.log("\n=== Test 2: main policy filter (no-op) ===");
{
  const input = [
    "Result",
    "<<SEND_FILE:C:\\test\\file.png>>",
    "<<ASK:q2|x=X|y=Y>>",
    "<<SCHEDULE:30m|do something>>",
    "<<RESTART:update>>",
    "<<STICKER:sad>>",
  ].join("\n");

  const reply = transform(input, stubParsers);
  const filtered = filterTransformedByPolicy(reply, "main");

  // 所有欄位與原 reply 相等
  let allMatch = true;
  for (const key of Object.keys(reply)) {
    if (!eq(reply[key], filtered[key])) {
      fail(`main: field ${key} unchanged`, `reply=${JSON.stringify(reply[key])} filtered=${JSON.stringify(filtered[key])}`);
      allMatch = false;
    }
  }
  if (allMatch) {
    ok("main: all fields unchanged (pass-through)");
  }
}

// ═══════════════════════════════════════════════════════════════════════════════
// Test 3: parseRememberTokens 上限截斷
// ═══════════════════════════════════════════════════════════════════════════════

console.log("\n=== Test 3: parseRememberTokens cap ===");
{
  const tokens = [
    "<<REMEMBER:fact one>>",
    "<<REMEMBER:fact two>>",
    "<<REMEMBER:  fact three  >>",
    "<<REMEMBER:fact four>>",
    "<<REMEMBER:fact five>>",
    "<<REMEMBER:fact six>>",
    "<<REMEMBER:fact seven>>",
  ].join("\nsome text\n");

  const parsed = parseRememberTokens(tokens);

  // 預設 cap=5，只回 5 條
  if (parsed.length === 5) {
    ok("parseRememberTokens: 7 tokens → 5 returned (cap)");
  } else {
    fail("parseRememberTokens: 7 tokens → 5 returned (cap)", `got ${parsed.length}`);
  }

  // 內容正確 trim
  if (parsed[0] === "fact one") {
    ok("parseRememberTokens: first fact correct");
  } else {
    fail("parseRememberTokens: first fact correct", `got '${parsed[0]}'`);
  }

  if (parsed[2] === "fact three") {
    ok("parseRememberTokens: trimmed whitespace");
  } else {
    fail("parseRememberTokens: trimmed whitespace", `got '${parsed[2]}'`);
  }

  if (parsed[4] === "fact five") {
    ok("parseRememberTokens: fifth fact correct (last before cap)");
  } else {
    fail("parseRememberTokens: fifth fact correct (last before cap)", `got '${parsed[4]}'`);
  }
}

// ═══════════════════════════════════════════════════════════════════════════════
// Test 4: parseRememberTokens 無超限時全數回傳
// ═══════════════════════════════════════════════════════════════════════════════

console.log("\n=== Test 4: parseRememberTokens under cap ===");
{
  const tokens = "<<REMEMBER:alpha>>\n<<REMEMBER:beta>>";
  const parsed = parseRememberTokens(tokens);
  if (parsed.length === 2 && parsed[0] === "alpha" && parsed[1] === "beta") {
    ok("parseRememberTokens: 2 tokens returned when under cap");
  } else {
    fail("parseRememberTokens: 2 tokens returned when under cap", `got ${JSON.stringify(parsed)}`);
  }
}

// ═══════════════════════════════════════════════════════════════════════════════
// Test 5: delegate policy — 全部清空
// ═══════════════════════════════════════════════════════════════════════════════

console.log("\n=== Test 5: delegate policy filter (empty all) ===");
{
  const input = [
    "Delegate output",
    "<<SEND_FILE:C:\\some\\path.txt>>",
    "<<ASK:dq|a=A>>",
    "<<STICKER:angry>>",
  ].join("\n");

  const reply = transform(input, stubParsers);
  const filtered = filterTransformedByPolicy(reply, "delegate");

  if (filtered.sendFiles.length === 0 && filtered.askTokens.length === 0 && filtered.stickerEmotions.length === 0) {
    ok("delegate: all token fields zeroed");
  } else {
    fail("delegate: all token fields zeroed", `sendFiles=${filtered.sendFiles.length} ask=${filtered.askTokens.length} sticker=${filtered.stickerEmotions.length}`);
  }

  if (filtered.text.includes("Delegate output")) {
    ok("delegate: text preserved");
  } else {
    fail("delegate: text preserved", `text='${filtered.text}'`);
  }
}

// ═══════════════════════════════════════════════════════════════════════════════
// Summary
// ═══════════════════════════════════════════════════════════════════════════════

console.log("\n" + "═".repeat(60));
const passed = results.filter((r) => r.pass).length;
const failed = results.filter((r) => !r.pass).length;
if (failed === 0) {
  console.log(`✅ ALL PASS (${passed} assertions)`);
  process.exit(0);
} else {
  console.error(`❌ ${failed} FAILED, ${passed} passed`);
  process.exit(1);
}

