/**
 * Token 執行權限顯式 policy 表。
 *
 * 設計意圖：「權限靠宣告不靠遺漏」。
 * 目前 proxy specialist 輸出的危險 token（SCHEDULE / RESTART / MOA_PLAN 等）
 * 只是剛好攝取點沒呼叫對應邏輯——未來 refactor 可能誤開。
 * 此模組以白名單形式宣告每個來源可以執行哪些 token kind，
 * filterTransformedByPolicy 在攝取點統一攔截非法 token。
 */

import type { TransformedReply } from "./observerTransformer.js";

// ─── 型別 ─────────────────────────────────────────────────────────────────────

/** Token 來源。 */
export type TokenSource = "main" | "proxy" | "delegate";

/** 所有可辨識的 token 種類（與 TransformedReply 欄位一一對應）。 */
export type TokenKind =
  | "sendFiles"
  | "scheduleTokens"
  | "askTokens"
  | "skillUsages"
  | "goalDone"
  | "restartToken"
  | "stickerEmotions"
  | "skillPropose"
  | "wikiQuery"
  | "continueToken"
  | "specialistProxy"
  | "moaPlan"
  | "rememberFacts";

// ─── Policy 表 ────────────────────────────────────────────────────────────────

/**
 * 各來源允許執行的 token 白名單。
 * - main：全部開放（主 agent 路徑完全信任）。
 * - proxy：僅限安全的 UI / 記憶類 token。
 * - delegate：delegate 輸出只當文字注入主 agent，不執行任何 token。
 */
export const TOKEN_POLICY: Record<TokenSource, ReadonlySet<TokenKind>> = {
  main: new Set<TokenKind>([
    "sendFiles",
    "scheduleTokens",
    "askTokens",
    "skillUsages",
    "goalDone",
    "restartToken",
    "stickerEmotions",
    "skillPropose",
    "wikiQuery",
    "continueToken",
    "specialistProxy",
    "moaPlan",
    "rememberFacts",
  ]),
  proxy: new Set<TokenKind>([
    "sendFiles",
    "askTokens",
    "skillUsages",
    "stickerEmotions",
    "rememberFacts",
  ]),
  delegate: new Set<TokenKind>([]),
};

// ─── 過濾函式 ─────────────────────────────────────────────────────────────────

/** 每個 token kind 對應 TransformedReply 中的欄位名稱與歸零值的映射。 */
const FIELD_ZERO: Record<Exclude<TokenKind, "rememberFacts">, { key: keyof TransformedReply; zero: unknown }> = {
  sendFiles:       { key: "sendFiles",       zero: [] },
  scheduleTokens:  { key: "scheduleTokens",  zero: [] },
  askTokens:       { key: "askTokens",       zero: [] },
  skillUsages:     { key: "skillUsages",     zero: [] },
  goalDone:        { key: "goalDone",        zero: null },
  restartToken:    { key: "restartToken",    zero: null },
  stickerEmotions: { key: "stickerEmotions", zero: [] },
  skillPropose:    { key: "skillPropose",    zero: null },
  wikiQuery:       { key: "wikiQuery",       zero: null },
  continueToken:   { key: "continueToken",   zero: false },
  specialistProxy: { key: "specialistProxy", zero: null },
  moaPlan:         { key: "moaPlan",         zero: null },
};

/**
 * 依 policy 過濾 TransformedReply：不在允許集合的欄位強制歸零。
 * 回傳淺拷貝：top-level 欄位不影響原物件，但保留欄位的陣列元素仍與
 * 原 reply 共享 reference——呼叫端應唯讀使用。text 保持不變。
 */
export function filterTransformedByPolicy(
  reply: TransformedReply,
  source: TokenSource,
): TransformedReply {
  const allowed = TOKEN_POLICY[source];
  const filtered: TransformedReply = { ...reply };
  const dropped: string[] = [];

  for (const [kind, mapping] of Object.entries(FIELD_ZERO) as Array<
    [Exclude<TokenKind, "rememberFacts">, { key: keyof TransformedReply; zero: unknown }]
  >) {
    if (allowed.has(kind)) continue;
    // 判斷原欄位是否有非空內容
    const val = reply[mapping.key];
    const isEmpty =
      val === null ||
      val === undefined ||
      val === false ||
      (Array.isArray(val) && val.length === 0);
    if (!isEmpty) {
      dropped.push(kind);
    }
    (filtered as unknown as Record<string, unknown>)[mapping.key] = mapping.zero;
  }

  if (dropped.length > 0) {
    console.warn(`[token-policy] source=${source} dropped: ${dropped.join(",")}`);
  }

  return filtered;
}

// ─── Remember facts 上限 ─────────────────────────────────────────────────────

/** 單次 specialist 輸出允許回寫的最大 fact 條數。 */
export const REMEMBER_FACTS_MAX_PER_OUTPUT = 5;

