  } else {
    fail("isTokenAllowed: main restartToken allowed", "got false");
  }
  if (isTokenAllowed("proxy", "scheduleTokens") === false) {
    ok("isTokenAllowed: proxy scheduleTokens denied");
  } else {
    fail("isTokenAllowed: proxy scheduleTokens denied", "got true");
  }
}

// ═══════════════════════════════════════════════════════════════════════════════
// Summary
